# ── Helper functions ──────────────────────────────────────────────────────────
def app_icon(symbol: str, color: str, size: str = "") -> str:
    cls = f"app-icon {color} {size}".strip()
    return f'<div class="{cls}">{symbol}</div>'

def section_header(symbol: str, color: str, title: str, subtitle: str = "") -> None:
    sub_html = f"<p>{subtitle}</p>" if subtitle else ""
    st.markdown(
        f"""
        <div class="section-header">
            {app_icon(symbol, color, "small")}
            <div><h2>{title}</h2>{sub_html}</div>
        </div>
        """,
        unsafe_allow_html=True,
    )

def mac_metric(col, symbol: str, color: str, label: str, value: str,
               delta: str = None, sentiment: str = "neutral") -> None:
    delta_html = f'<span class="delta {sentiment}">{delta}</span>' if delta else ""
    col.markdown(
        f"""
        <div class="mac-metric-card">
            <div class="icon-row">{app_icon(symbol, color, "small")}{delta_html}</div>
            <div class="value">{value}</div>
            <div class="label">{label}</div>
        </div>
        """,
        unsafe_allow_html=True,
    )

def style_chart(fig, accent="#1B3A6B"):
    fig.update_layout(
        title_font=dict(size=14, color="#1B3A6B", family="-apple-system, Helvetica Neue, Arial"),
        title_x=0.01,
        plot_bgcolor="rgba(0,0,0,0)",
        paper_bgcolor="rgba(0,0,0,0)",
        font=dict(family="-apple-system, Helvetica Neue, Arial", color="#1D1D1F", size=11),
        legend=dict(orientation="h", yanchor="bottom", y=1.06, xanchor="left", x=0,
                    title=None, bgcolor="rgba(0,0,0,0)"),
        margin=dict(l=10, r=10, t=70, b=10),
        hoverlabel=dict(bgcolor="white", font_size=12),
    )
    fig.update_xaxes(showgrid=False, linecolor="rgba(0,0,0,0.08)", tickfont=dict(size=10))
    fig.update_yaxes(showgrid=True, gridcolor="rgba(0,0,0,0.06)", zeroline=False)
    return fig

