with st.sidebar:
    st.markdown(
        f"""
        <div style="text-align:center; padding:12px 0 18px;">
            <img src="data:image/jpeg;base64,{TIH_LOGO_B64}"
                 style="max-width:160px; border-radius:10px;" alt="TIH Logo" />
        </div>
        """,
        unsafe_allow_html=True,
    )
    st.markdown(
        f"""
        <div class="section-header" style="margin-bottom:12px;">
            {app_icon("📋", "navy", "small")}
            <div><h2 style="font-size:15px;color:#1B3A6B;">Required Schema</h2></div>
        </div>
        <div class="mac-sidebar-card">
            <p style="font-size:12px;color:#6E6E73;margin:0 0 8px;">
                Upload an Excel or CSV with these exact column headers:
            </p>
            <ul>
                <li><b>Business_Unit</b></li>
                <li><b>Programme</b></li>
                <li><b>Financial_Year</b></li>
                <li><b>Quarter</b></li>
                <li><b>Budget_ZAR</b></li>
                <li><b>Actual_Expenditure_ZAR</b></li>
                <li><b>Revenue_Generated_ZAR</b></li>
                <li><b>Grant_Funding_ZAR</b></li>
                <li><b>Net_Benefit_ZAR</b></li>
                <li><b>ROI_Percent</b></li>
                <li><b>Budget_Utilisation_Percent</b></li>
                <li><b>KPI_Target_Percent</b></li>
                <li><b>KPI_Actual_Percent</b></li>
            </ul>
        </div>
        <hr style="margin:18px 0;">
        <div style="font-size:11px;color:#6E6E73;text-align:center;">
            A subsidiary of the<br>Gauteng Growth &amp; Development Agency
        </div>
        """,
        unsafe_allow_html=True,
    )

# ── File upload ───────────────────────────────────────────────────────────────
section_header("📂", "navy", "Upload Financial Report")
uploaded_file = st.file_uploader(
    "Choose an Excel or CSV file (FY 2025/2026)",
    type=["xlsx", "xls", "csv"],
    label_visibility="collapsed",
)

if uploaded_file is not None:
    try:
        if uploaded_file.name.endswith(".csv"):
            df = pd.read_csv(uploaded_file)
        else:
            df = pd.read_excel(uploaded_file)

        df.columns = [str(c).strip() for c in df.columns]
        missing_cols = [c for c in REQUIRED_COLUMNS if c not in df.columns]

        if missing_cols:
            st.error("❌ **Upload Failed — Missing Required Columns**")
            st.warning(f"Missing: `{missing_cols}`")
            st.info("Please align your file headers to the standard TIH Financial KPI schema shown in the sidebar.")
        else:
            st.success("✅ Financial report verified — ready to generate dashboard.")

            # ── Session-state generate button ─────────────────────────────────
            if "tih_generated" not in st.session_state:
                st.session_state.tih_generated = False
            if st.button("📊 Generate Financial KPI Dashboard", type="primary"):
                st.session_state.tih_generated = True

            if st.session_state.tih_generated:

                # Derived columns
                df["Budget_Variance_ZAR"]   = df["Budget_ZAR"] - df["Actual_Expenditure_ZAR"]
                df["KPI_Variance_Pct"]       = df["KPI_Actual_Percent"] - df["KPI_Target_Percent"]
                df["Benefit_Cost_Ratio"]     = (df["Net_Benefit_ZAR"] / df["Budget_ZAR"]).round(2)

                st.markdown("<div class=\'tih-swoosh\'></div>", unsafe_allow_html=True)

                # ── Search & Filter ───────────────────────────────────────────
                section_header("🔍", "orange", "Search & Filter Portfolio")
                st.markdown('<div class="mac-filter-bar">', unsafe_allow_html=True)

                f_r1c1, f_r1c2, f_r1c3 = st.columns([2, 1, 1])
                with f_r1c1:
                    search_term = st.text_input(
                        "search", placeholder="🔎  Search by programme or business unit…",
                        label_visibility="collapsed"
                    )
                with f_r1c2:
                    bus_units = ["All"] + sorted(df["Business_Unit"].dropna().unique().tolist())
                    sel_bu = st.selectbox("Business Unit", bus_units)
                with f_r1c3:
                    quarters = ["All"] + sorted(df["Quarter"].dropna().unique().tolist())
                    sel_q   = st.selectbox("Quarter", quarters)

                f_r2c1, f_r2c2, f_r2c3 = st.columns(3)
                roi_lo, roi_hi      = float(df["ROI_Percent"].min()),                float(df["ROI_Percent"].max())
                bud_lo, bud_hi      = float(df["Budget_ZAR"].min()),                 float(df["Budget_ZAR"].max())
                util_lo, util_hi    = float(df["Budget_Utilisation_Percent"].min()), float(df["Budget_Utilisation_Percent"].max())

                with f_r2c1:
                    roi_range  = st.slider("ROI %", roi_lo, roi_hi, (roi_lo, roi_hi))
                with f_r2c2:
                    bud_range  = st.slider("Budget (R)", bud_lo, bud_hi, (bud_lo, bud_hi))
                with f_r2c3:
                    util_range = st.slider("Budget Utilisation %", util_lo, util_hi, (util_lo, util_hi))

                # Apply filters
                fdf = df.copy()
                if search_term:
                    mask = (
                        fdf["Programme"].str.contains(search_term, case=False, na=False) |
                        fdf["Business_Unit"].str.contains(search_term, case=False, na=False)
                    )
                    fdf = fdf[mask]
                if sel_bu != "All":
                    fdf = fdf[fdf["Business_Unit"] == sel_bu]
                if sel_q != "All":
                    fdf = fdf[fdf["Quarter"] == sel_q]
                fdf = fdf[
                    fdf["ROI_Percent"].between(*roi_range) &
                    fdf["Budget_ZAR"].between(*bud_range) &
                    fdf["Budget_Utilisation_Percent"].between(*util_range)
                ]

                st.markdown(
                    f'<div class="mac-filter-count">Showing <b>{len(fdf)}</b> of <b>{len(df)}</b> programmes</div>',
                    unsafe_allow_html=True,
                )
                st.markdown('</div>', unsafe_allow_html=True)

                if fdf.empty:
                    st.warning("⚠️ No programmes match the current filters. Try widening your selection.")
                else:
                    st.write("")
                    # ── Executive Summary Metrics ─────────────────────────────
                    section_header("🎯", "navy", "Financial Executive Summary",
                                   "Aggregated KPIs across filtered portfolio")
                    m1, m2, m3, m4, m5 = st.columns(5)

                    total_budget  = fdf["Budget_ZAR"].sum()
                    total_spend   = fdf["Actual_Expenditure_ZAR"].sum()
                    total_rev     = fdf["Revenue_Generated_ZAR"].sum()
                    total_grant   = fdf["Grant_Funding_ZAR"].sum()
                    total_net     = fdf["Net_Benefit_ZAR"].sum()
                    avg_roi       = fdf["ROI_Percent"].mean()
                    avg_util      = fdf["Budget_Utilisation_Percent"].mean()
                    variance      = total_budget - total_spend

                    mac_metric(m1, "💰", "navy",   "Total Budget",
                               f"R {total_budget:,.0f}")
                    mac_metric(m2, "📤", "orange", "Total Expenditure",
                               f"R {total_spend:,.0f}",
                               delta=f"R {variance:,.0f} {'under' if variance>=0 else 'over'} budget",
                               sentiment="positive" if variance >= 0 else "negative")
                    mac_metric(m3, "📥", "green",  "Revenue Generated",
                               f"R {total_rev:,.0f}")
                    mac_metric(m4, "🏛️", "blue",   "Grant Funding",
                               f"R {total_grant:,.0f}")
                    mac_metric(m5, "📈", "teal",   "Avg ROI",
                               f"{avg_roi:.1f}%",
                               delta=f"{avg_util:.1f}% utilisation",
                               sentiment="positive" if avg_util <= 100 else "negative")

                    st.write("")
                    st.markdown("<div class=\'tih-swoosh\'></div>", unsafe_allow_html=True)

                    # ── Row 1 charts ──────────────────────────────────────────
                    section_header("📊", "orange", "Performance & Budgetary Insights")
                    c1, c2 = st.columns(2)

                    with c1:
                        df_m = fdf.melt(
                            id_vars=["Programme"],
                            value_vars=["Budget_ZAR", "Actual_Expenditure_ZAR", "Revenue_Generated_ZAR"],
                            var_name="Type", value_name="Amount (R)"
                        )
                        label_map = {"Budget_ZAR": "Budget", "Actual_Expenditure_ZAR": "Expenditure", "Revenue_Generated_ZAR": "Revenue"}
                        df_m["Type"] = df_m["Type"].map(label_map)
                        fig1 = px.bar(df_m, x="Programme", y="Amount (R)", color="Type",
                                      barmode="group",
                                      title="Budget · Expenditure · Revenue by Programme",
                                      color_discrete_map={"Budget": TIH_NAVY, "Expenditure": TIH_ORANGE, "Revenue": TIH_GREEN})
                        st.plotly_chart(style_chart(fig1), use_container_width=True)

                    with c2:
                        fig2 = px.bar(
                            fdf.sort_values("ROI_Percent", ascending=False),
                            x="Programme", y="ROI_Percent",
                            title="ROI % by Programme",
                            color="ROI_Percent",
                            color_continuous_scale=[TIH_RED, TIH_ORANGE, TIH_GREEN],
                        )
                        st.plotly_chart(style_chart(fig2), use_container_width=True)

                    st.write("")

                    # ── Row 2 charts ──────────────────────────────────────────
                    c3, c4 = st.columns(2)

                    with c3:
                        bu_grp = fdf.groupby("Business_Unit")[["Budget_ZAR","Revenue_Generated_ZAR","Net_Benefit_ZAR"]].sum().reset_index()
                        fig3 = px.pie(bu_grp, values="Net_Benefit_ZAR", names="Business_Unit",
                                      title="Net Benefit Distribution by Business Unit",
                                      hole=0.55, color_discrete_sequence=TIH_QUAL)
                        fig3.update_traces(textfont_size=11, marker=dict(line=dict(color="white", width=2)))
                        st.plotly_chart(style_chart(fig3), use_container_width=True)

                    with c4:
                        fig4 = px.bar(
                            fdf, x="Programme", y="KPI_Variance_Pct",
                            title="KPI Achievement Variance (+ = above target)",
                            color="KPI_Variance_Pct",
                            color_continuous_scale=[TIH_RED, "#FFD60A", TIH_GREEN],
                        )
                        fig4.add_hline(y=0, line_dash="dot", line_color=TIH_NAVY, opacity=0.5)
                        st.plotly_chart(style_chart(fig4), use_container_width=True)

                    st.write("")

                    # ── Row 3 charts ──────────────────────────────────────────
                    c5, c6 = st.columns(2)

                    with c5:
                        fig5 = px.scatter(
                            fdf, x="Budget_Utilisation_Percent", y="ROI_Percent",
                            size="Budget_ZAR", color="Business_Unit",
                            title="Budget Utilisation vs ROI (bubble = Budget size)",
                            color_discrete_sequence=TIH_QUAL, size_max=45,
                            hover_data=["Programme", "Net_Benefit_ZAR"],
                        )
                        fig5.add_vline(x=100, line_dash="dot", line_color=TIH_ORANGE, opacity=0.6)
                        st.plotly_chart(style_chart(fig5), use_container_width=True)

                    with c6:
                        qtr_grp = fdf.groupby("Quarter")[["Budget_ZAR","Actual_Expenditure_ZAR","Revenue_Generated_ZAR"]].sum().reset_index()
                        fig6 = go.Figure()
                        fig6.add_trace(go.Bar(name="Budget",      x=qtr_grp["Quarter"], y=qtr_grp["Budget_ZAR"],             marker_color=TIH_NAVY))
                        fig6.add_trace(go.Bar(name="Expenditure", x=qtr_grp["Quarter"], y=qtr_grp["Actual_Expenditure_ZAR"], marker_color=TIH_ORANGE))
                        fig6.add_trace(go.Bar(name="Revenue",     x=qtr_grp["Quarter"], y=qtr_grp["Revenue_Generated_ZAR"],  marker_color=TIH_GREEN))
                        fig6.update_layout(barmode="group", title="Quarterly Financial Summary")
                        st.plotly_chart(style_chart(fig6), use_container_width=True)

                    # ── Master portfolio grid ─────────────────────────────────
                    st.write("")
                    st.markdown("<div class=\'tih-swoosh\'></div>", unsafe_allow_html=True)
                    section_header("🗂️", "dark", "Innovation Hub · Projects Portfolio  FY 2025/2026")

                    display_df = fdf[[
                        "Business_Unit", "Programme", "Quarter",
                        "Budget_ZAR", "Actual_Expenditure_ZAR", "Budget_Variance_ZAR",
                        "Revenue_Generated_ZAR", "Grant_Funding_ZAR",
                        "Net_Benefit_ZAR", "ROI_Percent",
                        "Budget_Utilisation_Percent", "KPI_Target_Percent",
                        "KPI_Actual_Percent", "KPI_Variance_Pct", "Benefit_Cost_Ratio"
                    ]].rename(columns={
                        "Business_Unit":              "Business Unit",
                        "Programme":                  "Programme",
                        "Quarter":                    "Qtr",
                        "Budget_ZAR":                 "Budget (R)",
                        "Actual_Expenditure_ZAR":     "Expenditure (R)",
                        "Budget_Variance_ZAR":        "Variance (R)",
                        "Revenue_Generated_ZAR":      "Revenue (R)",
                        "Grant_Funding_ZAR":          "Grants (R)",
                        "Net_Benefit_ZAR":            "Net Benefit (R)",
                        "ROI_Percent":                "ROI %",
                        "Budget_Utilisation_Percent": "Utilisation %",
                        "KPI_Target_Percent":         "KPI Target %",
                        "KPI_Actual_Percent":         "KPI Actual %",
                        "KPI_Variance_Pct":           "KPI Var %",
                        "Benefit_Cost_Ratio":         "BCR",
                    })

                    st.dataframe(
                        display_df.style.format({
                            "Budget (R)":       "R{:,.0f}",
                            "Expenditure (R)":  "R{:,.0f}",
                            "Variance (R)":     "R{:,.0f}",
                            "Revenue (R)":      "R{:,.0f}",
                            "Grants (R)":       "R{:,.0f}",
                            "Net Benefit (R)":  "R{:,.0f}",
                            "ROI %":            "{:.1f}%",
                            "Utilisation %":    "{:.1f}%",
                            "KPI Target %":     "{:.1f}%",
                            "KPI Actual %":     "{:.1f}%",
                            "KPI Var %":        "{:+.1f}%",
                            "BCR":              "{:.2f}×",
                        }).applymap(
                            lambda v: "color:#1a6e35;font-weight:700" if isinstance(v, str) and v.startswith("+") else (
                                      "color:#b52b1e;font-weight:700" if isinstance(v, str) and v.startswith("-") else ""),
                            subset=["KPI Var %"]
                        ),
                        use_container_width=True,
                        height=420,
                    )

    except Exception as e:
        st.error(f"Error reading file. Please ensure the document is valid. Details: {e}")
